from collections import Counter
class Solution:
    def minChanges(self, nums, k):
        MAXX = 1024
        n = len(nums)
        cols = [Counter() for _ in range(k)]
        sizes = [0] * k
        for i, v in enumerate(nums):
            cols[i % k][v] += 1
            sizes[i % k] += 1
        INF = float('inf')
        dp = [INF] * MAXX
        dp[0] = 0
        for j in range(k):
            ndp = [INF] * MAXX
            for x in range(MAXX):
                if dp[x] == INF:
                    continue
                for val, cnt in cols[j].items():
                    nx = x ^ val
                    cost = dp[x] + (sizes[j] - cnt)
                    if cost < ndp[nx]:
                        ndp[nx] = cost
                base = dp[x] + sizes[j]
                for nx in range(MAXX):
                    if base < ndp[nx]:
                        ndp[nx] = base
            dp = ndp
        return dp[0]

