var minChanges = function(nums, k) {
    const MAXX = 1024;
    const n = nums.length;
    const cols = Array.from({length: k}, () => new Map());
    const sizes = new Array(k).fill(0);
    for (let i = 0; i < n; i++) {
        const c = cols[i % k];
        c.set(nums[i], (c.get(nums[i]) || 0) + 1);
        sizes[i % k]++;
    }
    const INF = Infinity;
    let dp = new Array(MAXX).fill(INF);
    dp[0] = 0;
    for (let j = 0; j < k; j++) {
        let best = INF;
        for (let x = 0; x < MAXX; x++) if (dp[x] < best) best = dp[x];
        const ndp = new Array(MAXX).fill(best + sizes[j]);
        for (let x = 0; x < MAXX; x++) {
            if (dp[x] === INF) continue;
            for (const [val, cnt] of cols[j]) {
                const nx = x ^ val;
                const cost = dp[x] + (sizes[j] - cnt);
                if (cost < ndp[nx]) ndp[nx] = cost;
            }
        }
        dp = ndp;
    }
    return dp[0];
};
